    params.append((random.uniform(k_, (192, 192), minval=-scale, maxval=scale), jnp.zeros(192)))
    # Transformer block 10 LN2
    params.append((jnp.ones(192), jnp.zeros(192)))
    # Transformer block 10 MLP fc1 192→768
    key, k_ = random.split(key)
    scale = jnp.sqrt(6.0 / 960)
    params.append((random.uniform(k_, (768, 192), minval=-scale, maxval=scale), jnp.zeros(768)))
    # Transformer block 10 MLP fc2 768→192
    key, k_ = random.split(key)
    scale = jnp.sqrt(6.0 / 960)
    params.append((random.uniform(k_, (192, 768), minval=-scale, maxval=scale), jnp.zeros(192)))
    # Transformer block 11 LN1
    params.append((jnp.ones(192), jnp.zeros(192)))
    # Transformer block 11 Q 192→192
    key, k_ = random.split(key)
    scale = jnp.sqrt(6.0 / 384)
    params.append((random.uniform(k_, (192, 192), minval=-scale, maxval=scale), jnp.zeros(192)))
    # Transformer block 11 K 192→192
    key, k_ = random.split(key)
    scale = jnp.sqrt(6.0 / 384)
    params.append((random.uniform(k_, (192, 192), minval=-scale, maxval=scale), jnp.zeros(192)))
    # Transformer block 11 V 192→192
    key, k_ = random.split(key)
    scale = jnp.sqrt(6.0 / 384)
    params.append((random.uniform(k_, (192, 192), minval=-scale, maxval=scale), jnp.zeros(192)))
    # Transformer block 11 Out 192→192
    key, k_ = random.split(key)
    scale = jnp.sqrt(6.0 / 384)
    params.append((random.uniform(k_, (192, 192), minval=-scale, maxval=scale), jnp.zeros(192)))
    # Transformer block 11 LN2
    params.append((jnp.ones(192), jnp.zeros(192)))
    # Transformer block 11 MLP fc1 192→768
    key, k_ = random.split(key)
    scale = jnp.sqrt(6.0 / 960)
    params.append((random.uniform(k_, (768, 192), minval=-scale, maxval=scale), jnp.zeros(768)))
    # Transformer block 11 MLP fc2 768→192
    key, k_ = random.split(key)
    scale = jnp.sqrt(6.0 / 960)
    params.append((random.uniform(k_, (192, 768), minval=-scale, maxval=scale), jnp.zeros(192)))
    # Final LN
    params.append((jnp.ones(192), jnp.zeros(192)))
    # Dense 192→10
    key, k_ = random.split(key)
    scale = jnp.sqrt(6.0 / 202)
    params.append((random.uniform(k_, (10, 192), minval=-scale, maxval=scale), jnp.zeros(10)))
    return params

