    """Mirror of init_params_from_file. Walks the JAX `params`
    list in spec order and serializes each tensor as float32 bytes
    in the same on-disk byte layout the phase-3 Lean trainer uses.
    Drop the resulting .bin into TrainConfig.bootstrapBackbone.
    """
    idx = 0
    f = open(path, 'wb')
    # patchEmbed conv W, b
    W, b = params[idx]; idx += 1
    f.write(np.asarray(W).astype(np.float32).flatten().tobytes())
    f.write(np.asarray(b).astype(np.float32).flatten().tobytes())
